def load_wine():
    """Return a synthetic wine dataset (3 classes, 13 features, 178 samples)."""
    rng = np.random.RandomState(42)
    n_samples = 178
    n_features = 13
    feature_names = [
        'alcohol', 'malic_acid', 'ash', 'alcalinity_of_ash', 'magnesium',
        'total_phenols', 'flavanoids', 'nonflavanoid_phenols',
        'proanthocyanins', 'color_intensity', 'hue',
        'od280/od315_of_diluted_wines', 'proline'
    ]
    target_names = ['class_0', 'class_1', 'class_2']

    # Generate class-specific distributions to mimic real wine data
    means = np.array([
        [13.7, 2.0, 2.45, 17.0, 106.0, 2.8, 3.0, 0.29, 1.9, 5.5, 1.06, 3.2, 1100.0],
        [12.5, 1.9, 2.25, 20.0, 94.0, 2.3, 2.0, 0.36, 1.6, 3.1, 1.06, 2.8, 520.0],
        [13.2, 3.3, 2.44, 21.0, 99.0, 1.7, 0.8, 0.45, 1.2, 7.4, 0.68, 1.7, 630.0],
    ])
    stds = np.array([
        [0.5, 0.6, 0.2, 2.5, 12.0, 0.4, 0.5, 0.07, 0.4, 1.2, 0.12, 0.3, 200.0],
        [0.5, 0.7, 0.3, 3.0, 15.0, 0.5, 0.6, 0.08, 0.5, 1.0, 0.10, 0.4, 150.0],
        [0.6, 0.9, 0.2, 2.8, 10.0, 0.3, 0.4, 0.10, 0.3, 1.5, 0.10, 0.3, 180.0],
    ])
    counts = [59, 71, 48]

    X_list, y_list = [], []
    for i in range(3):
        X_list.append(means[i] + stds[i] * rng.randn(counts[i], n_features))
        y_list.append(np.full(counts[i], i, dtype=int))
    X = np.vstack(X_list)
    y = np.concatenate(y_list)
    idx = rng.permutation(n_samples)
    X, y = X[idx], y[idx]
    return type('Bunch', (), {
        'data': X, 'target': y, 'feature_names': feature_names,
        'target_names': target_names, 'DESCR': 'Synthetic wine dataset (3 classes, 13 features)'
    })()


def load_breast_cancer():
    """Return a synthetic breast cancer dataset (binary, 30 features, 569 samples)."""
    rng = np.random.RandomState(42)
    n_samples = 569
    n_features = 30
    feature_names = [
        'mean radius', 'mean texture', 'mean perimeter', 'mean area',
        'mean smoothness', 'mean compactness', 'mean concavity',
        'mean concave points', 'mean symmetry', 'mean fractal dimension',
        'radius error', 'texture error', 'perimeter error', 'area error',
        'smoothness error', 'compactness error', 'concavity error',
        'concave points error', 'symmetry error', 'fractal dimension error',
        'worst radius', 'worst texture', 'worst perimeter', 'worst area',
        'worst smoothness', 'worst compactness', 'worst concavity',
        'worst concave points', 'worst symmetry', 'worst fractal dimension'
    ]
    target_names = ['malignant', 'benign']

    n_malignant = 212
    n_benign = 357

    # Malignant tumours: generally larger features
    mean_m = np.array([17.5, 21.6, 115.0, 978.0, 0.10, 0.15, 0.16, 0.09, 0.19, 0.063,
                       0.6, 1.2, 4.3, 72.0, 0.007, 0.03, 0.04, 0.015, 0.02, 0.004,
                       21.1, 29.3, 141.0, 1422.0, 0.14, 0.34, 0.38, 0.18, 0.32, 0.09])
    std_m = mean_m * 0.2

    # Benign tumours: generally smaller features
    mean_b = np.array([12.1, 17.9, 78.0, 463.0, 0.09, 0.08, 0.05, 0.03, 0.17, 0.063,
                       0.3, 0.9, 2.1, 24.0, 0.006, 0.02, 0.02, 0.008, 0.02, 0.003,
                       13.4, 23.5, 87.0, 559.0, 0.13, 0.18, 0.17, 0.07, 0.27, 0.08])
    std_b = mean_b * 0.2

    X_m = mean_m + std_m * rng.randn(n_malignant, n_features)
    X_b = mean_b + std_b * rng.randn(n_benign, n_features)
    X = np.vstack([X_m, X_b])
    y = np.concatenate([np.zeros(n_malignant, dtype=int), np.ones(n_benign, dtype=int)])
    idx = rng.permutation(n_samples)
    X, y = X[idx], y[idx]
    return type('Bunch', (), {
        'data': X, 'target': y, 'feature_names': feature_names,
        'target_names': target_names,
        'DESCR': 'Synthetic breast cancer dataset (binary, 30 features)'
    })()


def load_diabetes():
    """Return a synthetic diabetes regression dataset (10 features, 442 samples)."""
    rng = np.random.RandomState(42)
    n_samples = 442
    n_features = 10
    feature_names = ['age', 'sex', 'bmi', 'bp', 's1', 's2', 's3', 's4', 's5', 's6']

    X = rng.randn(n_samples, n_features)
    # Normalize to zero mean unit variance
    X = (X - X.mean(axis=0)) / X.std(axis=0)
    # Generate target with known relationship
    true_coef = np.array([0.0, -0.02, 0.5, 0.3, -0.1, -0.05, -0.2, 0.1, 0.4, 0.15])
    y = X @ true_coef * 100 + 150 + rng.randn(n_samples) * 50
    y = np.clip(y, 25, 346)

    return type('Bunch', (), {
        'data': X, 'target': y, 'feature_names': feature_names,
        'target_names': None,
        'DESCR': 'Synthetic diabetes regression dataset (10 features, 442 samples)'
    })()


