def make_swiss_roll(n_samples=100, *, noise=0.0, random_state=None, hole=False):
    """Generate a Swiss roll dataset in 3D."""
    rng = np.random.RandomState(random_state)
    t = 1.5 * np.pi * (1 + 2 * rng.uniform(size=n_samples))
    if hole:
        # Create a hole by removing points in the middle
        mask = np.abs(t - 3 * np.pi) > np.pi * 0.5
        while np.sum(mask) < n_samples:
            extra_t = 1.5 * np.pi * (1 + 2 * rng.uniform(size=n_samples))
            extra_mask = np.abs(extra_t - 3 * np.pi) > np.pi * 0.5
            t = np.concatenate([t[mask], extra_t[extra_mask]])
            mask = np.ones(len(t), dtype=bool)
        t = t[:n_samples]

    x = t * np.cos(t)
    y = rng.uniform(0, 21, size=n_samples)
    z = t * np.sin(t)

    X = np.column_stack([x, y, z])
    if noise > 0:
        X += noise * rng.randn(n_samples, 3)

    return X, t


def make_s_curve(n_samples=100, *, noise=0.0, random_state=None):
    """Generate an S-curve dataset in 3D."""
    rng = np.random.RandomState(random_state)
    t = 3 * np.pi * (rng.uniform(size=n_samples) - 0.5)
    x = np.sin(t)
    y = rng.uniform(0, 2, size=n_samples)
    z = np.sign(t) * (np.cos(t) - 1)

    X = np.column_stack([x, y, z])
    if noise > 0:
        X += noise * rng.randn(n_samples, 3)

    return X, t


def make_friedman1(n_samples=100, n_features=10, *, noise=0.0, random_state=None):
    """Generate the Friedman #1 regression dataset.

    y = 10 * sin(pi * x1 * x2) + 20 * (x3 - 0.5)^2 + 10 * x4 + 5 * x5 + noise
    """
    rng = np.random.RandomState(random_state)
    n_features = max(n_features, 5)
    X = rng.uniform(size=(n_samples, n_features))
    y = (10 * np.sin(np.pi * X[:, 0] * X[:, 1])
         + 20 * (X[:, 2] - 0.5) ** 2
         + 10 * X[:, 3]
         + 5 * X[:, 4])
    if noise > 0:
        y += noise * rng.randn(n_samples)
    return X, y


def make_friedman2(n_samples=100, *, noise=0.0, random_state=None):
    """Generate the Friedman #2 regression dataset.

    y = (x1^2 + (x2 * x3 - 1/(x2 * x4))^2)^0.5 + noise
    """
    rng = np.random.RandomState(random_state)
    x1 = rng.uniform(0, 100, size=n_samples)
    x2 = rng.uniform(40 * np.pi, 560 * np.pi, size=n_samples)
    x3 = rng.uniform(0, 1, size=n_samples)
    x4 = rng.uniform(1, 11, size=n_samples)
    y = np.sqrt(x1 ** 2 + (x2 * x3 - 1.0 / (x2 * x4)) ** 2)
    if noise > 0:
        y += noise * rng.randn(n_samples)
    X = np.column_stack([x1, x2, x3, x4])
    return X, y


def make_friedman3(n_samples=100, *, noise=0.0, random_state=None):
    """Generate the Friedman #3 regression dataset.

    y = atan((x2 * x3 - 1/(x2 * x4)) / x1) + noise
    """
    rng = np.random.RandomState(random_state)
    x1 = rng.uniform(0, 100, size=n_samples)
    x2 = rng.uniform(40 * np.pi, 560 * np.pi, size=n_samples)
    x3 = rng.uniform(0, 1, size=n_samples)
    x4 = rng.uniform(1, 11, size=n_samples)
    y = np.arctan((x2 * x3 - 1.0 / (x2 * x4)) / x1)
    if noise > 0:
        y += noise * rng.randn(n_samples)
    X = np.column_stack([x1, x2, x3, x4])
    return X, y
